import random
from datetime import datetime, timezone

SENSOR_TYPES = ["temperature", "humidity", "pressure", "voltage"]
UNITS = {
    "temperature": "C",
    "humidity": "%",
    "pressure": "hPa",
    "voltage": "V",
}

