for item in _items:
    payload = item["json"]
    # Webhook POST bodies arrive under "body"; manual start uses root fields.
    if isinstance(payload.get("body"), dict):
        state = payload["body"]
    else:
        state = payload

    cycle = int(state.get("cycle", 0))

    readings = []
    for index in range(5):
        sensor_type = SENSOR_TYPES[index % len(SENSOR_TYPES)]
        readings.append(
            {
                "sensor_id": f"SNR-{sensor_type[:3].upper()}-{index + 1:02d}",
                "sensor_type": sensor_type,
                "raw_value": round(random.uniform(10, 100), 2),
                "unit": UNITS[sensor_type],
                "timestamp": datetime.now(timezone.utc).isoformat(),
            }
        )

    results.append(
        {
            "json": {
                "cycle": cycle,
                "running": payload.get("running", True),
                "stage": "generated",
                "readings": readings,
                "generated_at": datetime.now(timezone.utc).isoformat(),
            }
        }
    )

return results

REQUIRED_FIELDS = ["sensor_id", "sensor_type", "raw_value", "unit", "timestamp"]
VALID_TYPES = {"temperature", "humidity", "pressure", "voltage"}
VALUE_RANGES = {
    "temperature": (-50, 150),
    "humidity": (0, 100),
    "pressure": (800, 1200),
    "voltage": (0, 500),
}

results = []

for item in _items:
    data = item["json"]
    readings = data.get("readings", [])
    validated = []
    errors = []

    for index, reading in enumerate(readings):
        missing = [field for field in REQUIRED_FIELDS if field not in reading]
        if missing:
            errors.append({"index": index, "error": f"Missing fields: {missing}"})
            continue

        sensor_type = reading["sensor_type"]
        if sensor_type not in VALID_TYPES:
            errors.append(
                {"index": index, "error": f"Invalid sensor_type: {sensor_type}"}
            )
            continue

        low, high = VALUE_RANGES[sensor_type]
        value = reading["raw_value"]
        if not isinstance(value, (int, float)) or value < low or value > high:
            errors.append(
                {
                    "index": index,
                    "error": f"Value {value} out of range [{low}, {high}]",
                }
            )
            continue

        validated.append({**reading, "valid": True})

    results.append(
        {
            "json": {
                "cycle": data.get("cycle", 0),
                "running": data.get("running", True),
                "stage": "validated",
                "readings": validated,
                "validation_errors": errors,
                "validation_passed": len(errors) == 0,
                "valid_count": len(validated),
                "generated_at": data.get("generated_at"),
            }
        }
    )

return results

NORMALIZATION = {
    "temperature": {"offset": 0, "scale": 1.0},
    "humidity": {"offset": 0, "scale": 1.0},
    "pressure": {"offset": 900, "scale": 0.1},
    "voltage": {"offset": 0, "scale": 0.01},
}

results = []

for item in _items:
    data = item["json"]
    normalized = []

    for reading in data.get("readings", []):
        config = NORMALIZATION[reading["sensor_type"]]
        raw_value = reading["raw_value"]
        normalized_value = round((raw_value - config["offset"]) * config["scale"], 4)
        normalized.append(
            {
                **reading,
                "normalized_value": normalized_value,
                "calibration_applied": True,
            }
        )

    results.append(
        {
            "json": {
                "cycle": data.get("cycle", 0),
                "running": data.get("running", True),
                "stage": "normalized",
                "validation_passed": data.get("validation_passed", False),
                "valid_count": data.get("valid_count", 0),
                "validation_errors": data.get("validation_errors", []),
                "readings": normalized,
            }
        }
    )

return results

import math

results = []

for item in _items:
    data = item["json"]
    readings = data.get("readings", [])

    values = [reading["normalized_value"] for reading in readings]
    count = len(values)

    if count == 0:
        mean = 0.0
        std = 0.0
    else:
        mean = sum(values) / count
        variance = sum((value - mean) ** 2 for value in values) / count
        std = math.sqrt(variance) if variance > 0 else 0.0

    flagged = []
    anomaly_count = 0

    for reading in readings:
        value = reading["normalized_value"]
        if std > 0:
            z_score = abs((value - mean) / std)
        else:
            z_score = 0.0

        is_anomaly = z_score > 1.5
        if is_anomaly:
            anomaly_count += 1

        if z_score > 2.5:
            severity = "critical"
        elif is_anomaly:
            severity = "warning"
        else:
            severity = "normal"

        flagged.append(
            {
                **reading,
                "z_score": round(z_score, 4),
                "is_anomaly": is_anomaly,
                "severity": severity,
            }
        )

    results.append(
        {
            "json": {
                "cycle": data.get("cycle", 0),
                "running": data.get("running", True),
                "stage": "anomaly_checked",
                "validation_passed": data.get("validation_passed", False),
                "valid_count": data.get("valid_count", 0),
                "readings": flagged,
                "batch_stats": {
                    "mean": round(mean, 4),
                    "std": round(std, 4),
                    "count": count,
                },
                "anomaly_count": anomaly_count,
            }
        }
    )

return results

from collections import defaultdict

results = []

for item in _items:
    data = item["json"]
    readings = data.get("readings", [])

    by_type = defaultdict(list)
    for reading in readings:
        by_type[reading["sensor_type"]].append(reading["normalized_value"])

    aggregates = {}
    for sensor_type, values in by_type.items():
        aggregates[sensor_type] = {
            "count": len(values),
            "min": round(min(values), 4),
            "max": round(max(values), 4),
            "avg": round(sum(values) / len(values), 4),
        }

    severity_counts = {"normal": 0, "warning": 0, "critical": 0}
    for reading in readings:
        severity = reading.get("severity", "normal")
        severity_counts[severity] = severity_counts.get(severity, 0) + 1

    results.append(
        {
            "json": {
                "cycle": data.get("cycle", 0),
                "running": data.get("running", True),
                "stage": "aggregated",
                "aggregates_by_type": aggregates,
                "severity_counts": severity_counts,
                "anomaly_count": data.get("anomaly_count", 0),
                "batch_stats": data.get("batch_stats", {}),
                "readings": readings,
            }
        }
    )

return results

from datetime import datetime, timezone

results = []

for item in _items:
    data = item["json"]
    cycle = int(data.get("cycle", 0))
    anomaly_count = data.get("anomaly_count", 0)
    severity_counts = data.get("severity_counts", {})

    if severity_counts.get("critical", 0) > 0:
        status = "CRITICAL"
    elif anomaly_count > 0:
        status = "DEGRADED"
    else:
        status = "HEALTHY"

    report_lines = [
        f"=== Sensor Pipeline Report | Cycle {cycle} ===",
        f"Status: {status}",
        f"Anomalies: {anomaly_count}",
        f"Severity: {severity_counts}",
    ]

    for sensor_type, aggregate in data.get("aggregates_by_type", {}).items():
        report_lines.append(
            "  "
            + f"{sensor_type}: avg={aggregate['avg']} "
            + f"min={aggregate['min']} max={aggregate['max']} "
            + f"(n={aggregate['count']})"
        )

    report_text = "\n".join(report_lines)

    results.append(
        {
            "json": {
                "cycle": cycle,
                "running": data.get("running", True),
                "stage": "complete",
                "status": status,
                "report": report_text,
                "summary": {
                    "cycle": cycle,
                    "status": status,
                    "anomaly_count": anomaly_count,
                    "severity_counts": severity_counts,
                    "aggregates_by_type": data.get("aggregates_by_type", {}),
                },
                "completed_at": datetime.now(timezone.utc).isoformat(),
                "next_cycle": cycle + 1,
                "loop_payload": {
                    "cycle": cycle + 1,
                    "running": True,
                },
            }
        }
    )

return results
